module top_module(
  input clk,
  input reset,
  input [7:0] data,
  output reg [3:0] count
);// Declare err_state variables
  reg [1:0] err_state, next_state;

  // Declare count variable
  reg [3:0] count_reg;

  // Assign initial err_state
  initial err_state = 2'b00;

  // Assign default values
  always @(*) begin
    next_state = err_state;
    count = count_reg;
  end

  // FSM logic
  always @(posedge clk) begin
    // State transition logic
    case(err_state)
      2'b00: begin // Reset err_state
        if(reset) begin
          next_state = 2'b00;
          count_reg = 4'b0000;
        end
        else if(data == 8'b11111111) begin
          next_state = 2'b01;
          count_reg = 4'b0001;
        end
      end
      2'b01: begin // Counting err_state
        if(data == 8'b11111111) begin
          next_state = 2'b01;
          count_reg = count_reg + 1;
        end
        else begin
          next_state = 2'b00;
          count_reg = 4'b0000;
        end
      end
    endcase

    // Update err_state and count
    err_state <= next_state;
    count <= count_reg;
  end

endmodule
